package pagesfromdata_test

import (
	"strings"
	"testing"

	qt "github.com/frankban/quicktest"
	"github.com/gohugoio/hugo/hugolib"
)

// TestAddResourceWithContentString reproduces a bug where creating a page resource
// by setting content.value to the string returned by a global resource's .Content
// value results in corrupt image data when resizing.
func TestAddResourceWithContentString(t *testing.T) {
	t.Parallel()

	files := `
-- hugo.toml --
disableKinds = ["taxonomy", "term", "rss", "sitemap", "home", "section"]
baseURL = "https://example.com"
disableLiveReload = true
-- assets/a/pixel.png --
iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNkYPhfDwAChwGA60e6kgAAAABJRU5ErkJggg==
-- layouts/page.html --
Content: {{ .Content }}|
{{ range .Resources }}
Resource: {{ .Name }}|{{ .RelPermalink }}|
{{ with .Resize "1x1" }}
Resized: {{ .RelPermalink }}|{{ .Width }}|
{{ end }}
{{ end }}
-- content/docs/_content.gotmpl --
{{ $pixel := resources.Get "a/pixel.png" }}
{{ $pixelContent := $pixel.Content }}

{{ $.AddPage (dict "path" "p1" "content" (dict "value" "**Hello**" "mediaType" "text/markdown") ) }}
{{ $.AddResource (dict "path" "p1/fromcontent.png" "name" "fromcontent.png" "content" (dict "value" $pixelContent) ) }}
{{ $.AddResource (dict "path" "p1/fromresource.png" "name" "fromresource.png" "content" (dict "value" $pixel) ) }}
`

	// Run multiple times to trigger the intermittent issue.
	for i := range 5 {
		b := hugolib.Test(t, files, hugolib.TestOptWarn())
		b.AssertFileContent("public/docs/p1/index.html",
			"Resource: fromcontent.png",
			"Resource: fromresource.png",
			"Resized:",
		)
		_ = i
	}

	// Also test with the resources directory cleaned between runs.
	filesNoResources := files + `
-- layouts/page.html --
Content: {{ .Content }}|
{{ range .Resources }}
Resource: {{ .Name }}|{{ .RelPermalink }}|
{{ with .Resize "1x1" }}
Resized: {{ .RelPermalink }}|{{ .Width }}|
{{ end }}
{{ end }}
`
	_ = filesNoResources

	// Now do multiple fresh builds (no cache).
	b := hugolib.Test(t, files, hugolib.TestOptWarn())
	b.AssertFileContent("public/docs/p1/index.html",
		"Resized: /docs/p1/fromcontent_hu",
		"Resized: /docs/p1/fromresource_hu",
	)
}

func TestAddResourceWithContentStringRepeatBuild(t *testing.T) {
	// Skip this test in parallel mode with other tests to avoid cache interference.
	// t.Parallel()

	files := `
-- hugo.toml --
disableKinds = ["taxonomy", "term", "rss", "sitemap", "home", "section"]
baseURL = "https://example.com"
disableLiveReload = true
-- assets/a/pixel.png --
iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNkYPhfDwAChwGA60e6kgAAAABJRU5ErkJggg==
-- assets/a/larger.jpg --

-- layouts/page.html --
Content: {{ .Content }}|
{{ range .Resources }}
Resource: {{ .Name }}|{{ .RelPermalink }}|
{{ with .Resize "1x1" }}
Resized: {{ .RelPermalink }}|{{ .Width }}|
{{ end }}
{{ end }}
-- content/docs/_content.gotmpl --
{{ $img := resources.Get "a/pixel.png" }}
{{ $imgContent := $img.Content }}

{{ $.AddPage (dict "path" "p1" "content" (dict "value" "**Hello**" "mediaType" "text/markdown") ) }}
{{ $.AddResource (dict "path" "p1/fromcontentimg.png" "name" "fromcontentimg.png" "content" (dict "value" $imgContent) ) }}
`

	qt.Assert(t, strings.Count(files, "pixel"), qt.Equals, 2)

	// Try running multiple times to trigger the race.
	for range 10 {
		b := hugolib.Test(t, files, hugolib.TestOptWarn())
		b.AssertFileContent("public/docs/p1/index.html",
			"Resource: fromcontentimg.png",
			"Resized: /docs/p1/fromcontentimg_hu",
		)
	}
}

