38	// Decoder defines the decoding of an image format.
39	// These matches the globalmpackage image functions.
40	type Decoder interface {
41		Decode(r io.Reader) (image.Image, error)
42		DecodeConfig(r io.Reader) (image.Config, error)
43	}
44	
45	type ToEncoder interface {
46		EncodeTo(conf ImageConfig, w io.Writer, src image.Image) error
47	}
48	
49	// EncoderWithOptions defines the encoding of an image format with the given options.
50	type Encoder interface {
51		Encode(w io.Writer, src image.Image, options map[string]any) error
52	}
53	
54	// EncodeDecoder defines both decoding and encoding of an image format as defined by the standard library.
55	type EncodeDecoder interface {
56		Decoder
57		Encoder
58	}
59	
60	// Codec is a generic image codec supporting multiple formats.
61	type Codec struct {
62		webp   EncodeDecoder
63		debugl logg.LevelLogger
64	}
65	
66	func newCodec(webp EncodeDecoder, debugl logg.LevelLogger) *Codec {
67		return &Codec{webp: webp, debugl: debugl}
68	}
69	
70	func (d *Codec) EncodeTo(conf ImageConfig, w io.Writer, img image.Image) error {
71		d.debugl.Log(
72			// This construct looks odd, but the func will only be called if debug is enabled.
73			logg.StringFunc(
74				func() string {
75					return fmt.Sprintf("Encoding image to format %s with config %+v", conf.TargetFormat, conf)
76				},
77			),
78		)
79		switch conf.TargetFormat {
80		case JPEG:
81			var rgba *image.RGBA
82			quality := conf.Quality
83	
84			if nrgba, ok := img.(*image.NRGBA); ok {
85				if nrgba.Opaque() {
86					rgba = &image.RGBA{
87						Pix:    nrgba.Pix,
88						Stride: nrgba.Stride,
89						Rect:   nrgba.Rect,
90					}
91				}
92			}
93			if rgba != nil {
94				return jpeg.Encode(w, rgba, &jpeg.Options{Quality: quality})
95			}
96			return jpeg.Encode(w, img, &jpeg.Options{Quality: quality})
97		case PNG:
98			encoder := png.Encoder{CompressionLevel: png.DefaultCompression}
99			return encoder.Encode(w, img)
100		case GIF:
101			if anim, ok := img.(himage.AnimatedImage); ok {
102				if g, ok := anim.GetRaw().(*gif.GIF); ok {
103					return gif.EncodeAll(w, g)
104				}
105	
106				// Animated image, but not a GIF. Convert it.
107				frames := anim.GetFrames()
108				if len(frames) == 0 {
109					return gif.Encode(w, img, &gif.Options{NumColors: 256})
110				}
111	
112				frameDurations := anim.GetFrameDurations()
113				if len(frameDurations) != len(frames) {
114					return errors.New("gif: number of frame durations does not match number of frames")
115				}
116	
117				outGif := &gif.GIF{
118					Delay: himage.FrameDurationsToGifDelays(frameDurations),
119				}
120	
121				outGif.LoopCount = anim.GetLoopCount()
122	
123				for _, frame := range frames {
124					bounds := frame.Bounds()
125					palettedImage := image.NewPaletted(bounds, palette.Plan9)
126					draw.Draw(palettedImage, palettedImage.Rect, frame, bounds.Min, draw.Src)
127					outGif.Image = append(outGif.Image, palettedImage)
128				}
129	
130				return gif.EncodeAll(w, outGif)
131			}
132			return gif.Encode(w, img, &gif.Options{
133				NumColors: 256,
134			})
135		case TIFF:
136			return tiff.Encode(w, img, &tiff.Options{Compression: tiff.Deflate, Predictor: true})
137		case BMP:
138			return bmp.Encode(w, img)
139		case WEBP:
140			// Convert bool to int because the C code reads it as a number.
141			useSharpYuvInt := 0
142			if conf.UseSharpYuv {
143				useSharpYuvInt = 1
144			}
145			opts := map[string]any{
146				"compression": conf.Compression,
147				"quality":     conf.Quality,
148				"hint":        conf.Hint,
149				"useSharpYuv": useSharpYuvInt,
150				"method":      conf.Method,
151			}
152			return d.webp.Encode(w, img, opts)
153		default:
154			return errors.New("format not supported")
155		}
156	}
157	
158	func (d *Codec) DecodeFormat(f Format, r io.Reader) (image.Image, error) {
159		d.debugl.Log(
160			logg.StringFunc(
161				func() string {
162					return fmt.Sprintf("Decoding image from format %s", f)
163				},
164			),
165		)
166		switch f {
167		case JPEG, PNG:
168			// We reworked this decode/encode setup to get full WebP support in v0.153.0.
169			// In the first take of that we used f to decide whether to call png.Decode or jpeg.Decode here,
170			// but testing it on some sites, it seems that it's not uncommon to store JPEGs with PNG extensions and vice versa.
171			// So, to reduce some noise in that release, we fallback to the standard library here,
172			// which will read the magic bytes and decode accordingly.
173			img, _, err := image.Decode(r)
174			return img, err
175		case GIF:
176			g, err := gif.DecodeAll(r)
177			if err != nil {
178				return nil, fmt.Errorf("failed to decode gif: %w", err)
179			}
180			if len(g.Delay) > 1 {
181				return &giphy{gif: g, Image: g.Image[0]}, nil
182			}
183			return g.Image[0], nil
184		case TIFF:
185			return tiff.Decode(r)
186		case BMP:
187			return bmp.Decode(r)
188		case WEBP:
189			img, err := d.webp.Decode(r)
190			if err == nil {
191				return img, nil
192			}
193			if rs, ok := r.(io.ReadSeeker); ok {
194				// See issue 14288. Turns out it's not uncommon to e.g. name their PNG files with a WEBP extension.
195				// With the old Go's webp decoder, this didn't fail (it looked for the file header),
196				// but now some error has surfaced.
197				// To reduce some noise, we try to reset and decode again using the standard library.
198				_, err2 := rs.Seek(0, io.SeekStart)
199				if err2 != nil {
200					return nil, err
201				}
202				img, _, err2 = image.Decode(rs)
203				if err2 == nil {
204					return img, nil
205				}
206			}
207			return nil, err
208		default:
209			return nil, errors.New("format not supported")
210		}
211	}
212	
213	func (d *Codec) Decode(r io.Reader) (image.Image, error) {
214		d.debugl.Log(
215			logg.StringFunc(
216				func() string {
217					return "Decoding image from unknown format"
218				},
219			),
220		)
221		rr := toPeekReader(r)
222		format, err := formatFromImage(rr)
223		if err != nil {
224			return nil, err
225		}
226		if format != 0 {
227			return d.DecodeFormat(format, rr)
228		}
229	
230		// Fallback to the standard image.Decode.
231		img, _, err := image.Decode(rr)
232		return img, err
233	}
234	
235	func (d *Codec) DecodeConfig(f Format, r io.Reader) (image.Config, string, error) {
236		rr := toPeekReader(r)
237		format, err := formatFromImage(rr)
238		if err != nil {
239			return image.Config{}, "", err
240		}
241		if format == 0 {
242			format = f
243		}
244		r = rr
245		if format.UseImageMetaConfigDecoder() {
246			rs, err := hugio.NewReadSeekerNoOpCloserFromReader(r)
247			if err != nil {
248				return image.Config{}, "", err
249			}
250			rs.Seek(0, 0)
251			res, err := imagemeta.Decode(
252				imagemeta.Options{
253					R:           rs,
254					ImageFormat: format.ToImageMetaImageFormatFormat(),
255					Sources:     imagemeta.CONFIG,
256				},
257			)
258			if err == nil {
259				return image.Config{
260					Width:      res.ImageConfig.Width,
261					Height:     res.ImageConfig.Height,
262					ColorModel: color.RGBAModel,
263				}, strings.ToLower(format.String()), nil
264			}
265	
266			// Fallback to the standard image.DecodeConfig.
267			rs.Seek(0, 0)
268			r = rs
269		}
270	
271		conf, name, err := image.DecodeConfig(r)
272	
273		return conf, name, err
274	}
275	
276	// toPeekReader converts an io.Reader to a peekReader.
277	func toPeekReader(r io.Reader) peekReader {
278		if rr, ok := r.(peekReader); ok {
279			return rr
280		}
281		return bufio.NewReader(r)
282	}
283	
284	// A peekReader is an io.Reader that can also peek ahead.
285	type peekReader interface {
286		io.Reader
287		Peek(int) ([]byte, error)
288	}
289	
290	const (
291		// The WebP file header is 12 bytes long and starts with "RIFF" followed by
292		// 4 bytes indicating the file size, followed by "WEBP" and the VP8 chunk header.
293		// We use '?' as a wildcard for the 4 size bytes.
294		magicWebp = "RIFF????WEBPVP8"
295		// The GIF file header is 6 bytes long and starts with "GIF87a" or "GIF89a".
296		magicGif = "GIF8???"
297	)
298	
299	type magicFormat struct {
300		magic  string
301		format Format
302	}
303	
304	var magicFormats = []magicFormat{
305		{magic: magicWebp, format: WEBP},
306		{magic: magicGif, format: GIF},
307	}
308	
309	// formatFromImage determines the image format from the magic bytes.
310	// Note that this is only a partial implementation,
311	// as we currently only need WebP and GIF detection.
312	// The others can be handled by the standard library.
313	func formatFromImage(r peekReader) (Format, error) {
314		for _, mf := range magicFormats {
315			magicLen := len(mf.magic)
316			b, err := r.Peek(magicLen)
317			if err == nil && match(mf.magic, b) {
318				return mf.format, nil
319			}
320		}
321		return 0, nil
322	}
323	
324	func match(magic string, b []byte) bool {
325		if len(magic) != len(b) {
326			return false
327		}
328		for i := 0; i < len(magic); i++ {
329			if magic[i] != '?' && magic[i] != b[i] {
330				return false
331			}
332		}
333		return true
334	}
335	
336	var (
337		_ himage.AnimatedImage       = (*giphy)(nil)
338		_ himage.ImageConfigProvider = (*giphy)(nil)
339	)
340	
341	type giphy struct {
342		image.Image
343		gif *gif.GIF
344	}
345	
346	func (g *giphy) GetRaw() any {
347		return g.gif
348	}
349	
350	func (g *giphy) GetLoopCount() int {
351		return g.gif.LoopCount
352	}
353	
354	func (g *giphy) GetFrames() []image.Image {
355		frames := make([]image.Image, len(g.gif.Image))
356		for i, frame := range g.gif.Image {
357			frames[i] = frame
358		}
359		return frames
360	}
361	
362	func (g *giphy) GetImageConfig() image.Config {
363		return g.gif.Config
364	}
365	
366	func (g *giphy) SetFrames(frames []image.Image) {
367		if len(frames) == 0 {
368			panic("frames cannot be empty")
369		}
370		g.gif.Image = make([]*image.Paletted, len(frames))
371		for i, frame := range frames {
372			g.gif.Image[i] = frame.(*image.Paletted)
373		}
374		g.Image = g.gif.Image[0]
375	}
376	
377	func (g *giphy) SetWidthHeight(width, height int) {
378		g.gif.Config.Width = width
379		g.gif.Config.Height = height
380	}
381	
382	func (g *giphy) GetFrameDurations() []int {
383		return himage.GifDelaysToFrameDurations(g.gif.Delay)
384	}
